SELECT 
    (SELECT user_name FROM users ORDER BY last_login DESC LIMIT 1) as MostRecentUser, 
    (SELECT error_type FROM error_logs GROUP BY error_type ORDER BY COUNT(*) DESC LIMIT 1) as MostCommonErrorType;

SELECT setting_value
FROM custom_settings
WHERE setting_key = 'custom_favicon_url';

SELECT search_engine_id, AVG(metric_value) AS avg_usage, source
FROM usage_metrics
GROUP BY search_engine_id, source;

SELECT users.user_name, configurations.setting_name
FROM users
JOIN configurations ON users.user_id = configurations.search_engine_id;

SELECT browser_name, integration_status
FROM browser_integrations
WHERE search_engine_id = 2;

SELECT search_engine_id, COUNT(*) AS number_of_accesses
FROM access_logs
GROUP BY search_engine_id;
